UPDATE public.questions SET
  stimulus_text = 'The speaker’s main goal is to persuade the reader that their favorite game is the best. The speaker’s argument relies on a series of reasons, each of which is meant to demonstrate the game’s unique appeal.  The speaker makes use of descriptive language to appeal to the reader’s senses.  In addition, the speaker uses a conversational tone to enhance the reader’s engagement with the passage. What is the main idea of the passage?',
  question_text = 'The passage is primarily intended to',
  stimulus_type = NULL,
